import{_ as a,o as i,c as t,ag as s}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Troubleshooting","description":"Common Foldergram issues and the exact implementation details behind them.","frontmatter":{"title":"Troubleshooting","description":"Common Foldergram issues and the exact implementation details behind them."},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md","lastUpdated":1780743085000}'),o={name:"troubleshooting.md"};function r(l,e,n,d,p,h){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="the-app-says-the-library-storage-is-unavailable" tabindex="-1">The app says the library storage is unavailable <a class="header-anchor" href="#the-app-says-the-library-storage-is-unavailable" aria-label="Permalink to &quot;The app says the library storage is unavailable&quot;">​</a></h2><p>Foldergram checks the configured:</p><ul><li>gallery directory</li><li>thumbnails directory</li><li>previews directory</li></ul><p>If any of those are unavailable, the UI reports the reason exposed by the backend.</p><p>Check:</p><ul><li>the configured paths in <code>.env</code></li><li>whether those paths exist</li><li>whether <code>DB_DIR</code>, <code>THUMBNAILS_DIR</code>, and <code>PREVIEWS_DIR</code> are writable by the current process</li><li>whether <code>&lt;DATA_ROOT&gt;/scan-errors</code> is writable if you use <code>SCAN_MEDIA_ERROR_MODE=skip</code></li></ul><p><code>GALLERY_ROOT</code> is scanned read-only. It does not need write access unless you use delete actions that remove originals from the gallery.</p><h2 id="the-database-keeps-resetting" tabindex="-1">The database keeps resetting <a class="header-anchor" href="#the-database-keeps-resetting" aria-label="Permalink to &quot;The database keeps resetting&quot;">​</a></h2><p>If <code>DB_DIR</code> is unavailable, Foldergram falls back to an in-memory SQLite database. That means indexed state disappears when the process stops.</p><p>Fix the configured database directory first.</p><h2 id="startup-stops-after-an-upgrade" tabindex="-1">Startup stops after an upgrade <a class="header-anchor" href="#startup-stops-after-an-upgrade" aria-label="Permalink to &quot;Startup stops after an upgrade&quot;">​</a></h2><p>Foldergram now runs pending SQLite migrations before it serves requests. If the app stops during startup, check the server or container logs first.</p><p>Check:</p><ul><li>whether <code>DB_DIR</code> still exists and is writable</li><li>whether the database volume or bind mount still points to the intended location</li><li>whether the filesystem has enough free space for the SQLite update</li></ul><p>For source installs, you can rerun the migration step directly with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span></span></code></pre></div><h2 id="nothing-is-being-indexed" tabindex="-1">Nothing is being indexed <a class="header-anchor" href="#nothing-is-being-indexed" aria-label="Permalink to &quot;Nothing is being indexed&quot;">​</a></h2><p>Start with the gallery structure rules:</p><ul><li>files directly inside <code>GALLERY_ROOT</code> are ignored</li><li>hidden folders are ignored</li><li>a folder is indexed only when it directly contains supported media</li></ul><p>This will not be indexed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gallery/</span></span>
<span class="line"><span>  loose-file.jpg</span></span>
<span class="line"><span>  trips/</span></span>
<span class="line"><span>    oslo/</span></span>
<span class="line"><span>      notes.txt</span></span></code></pre></div><p>This will be indexed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gallery/</span></span>
<span class="line"><span>  trips/</span></span>
<span class="line"><span>    oslo/</span></span>
<span class="line"><span>      IMG_0001.jpg</span></span></code></pre></div><h2 id="rescan-returns-a-rebuild-required-message" tabindex="-1">Rescan returns a rebuild-required message <a class="header-anchor" href="#rescan-returns-a-rebuild-required-message" aria-label="Permalink to &quot;Rescan returns a rebuild-required message&quot;">​</a></h2><p>This happens when the configured gallery root no longer validates against the existing indexed library.</p><p>If you moved the same library to a new location and every indexed file still exists at the same relative path with the same size, mtime, and extension, Foldergram refreshes stored source paths automatically at startup and keeps the existing index.</p><p>Use Settings or <code>POST /api/admin/rebuild-index</code> only when the new root is a different or incomplete library, or when relocation validation already failed.</p><h2 id="places-do-not-appear" tabindex="-1">Places do not appear <a class="header-anchor" href="#places-do-not-appear" aria-label="Permalink to &quot;Places do not appear&quot;">​</a></h2><p>Places are opt-in and only work for photos that already have GPS metadata.</p><p>Check:</p><ul><li><code>Settings -&gt; Places</code> has prepared the offline GeoNames dataset</li><li><code>Settings -&gt; Places</code> has run <code>Rebuild place assignments</code></li><li>the source photos actually contain GPS EXIF coordinates</li></ul><p>Videos and photos without GPS metadata do not appear in Places.</p><h2 id="i-moved-files-into-different-folders-and-expected-them-to-stay-the-same-post" tabindex="-1">I moved files into different folders and expected them to stay the same post <a class="header-anchor" href="#i-moved-files-into-different-folders-and-expected-them-to-stay-the-same-post" aria-label="Permalink to &quot;I moved files into different folders and expected them to stay the same post&quot;">​</a></h2><p>After the derivative-layout upgrade migration has completed, full rescans can preserve the same indexed row, likes, and derivative paths for safe file moves.</p><p>Check:</p><ul><li>that a full scan has already completed since the upgrade</li><li>that the moved file kept the same size and modification time</li><li>that the old source path is genuinely gone, not duplicated</li></ul><p>If a move is ambiguous, Foldergram falls back to the older delete-and-new behavior to avoid matching the wrong file.</p><h2 id="old-thumbnails-or-previews-are-still-on-disk-after-files-disappeared" tabindex="-1">Old thumbnails or previews are still on disk after files disappeared <a class="header-anchor" href="#old-thumbnails-or-previews-are-still-on-disk-after-files-disappeared" aria-label="Permalink to &quot;Old thumbnails or previews are still on disk after files disappeared&quot;">​</a></h2><p>Missing originals are soft-deleted first. Stale derivatives are cleaned up only after the retention window on a later successful full scan.</p><p>That is intentional so temporary share outages or accidental moves do not immediately delete cached derivatives.</p><h2 id="a-scan-failed-or-completed-with-errors-on-a-corrupt-or-unreadable-media-file" tabindex="-1">A scan failed or completed with errors on a corrupt or unreadable media file <a class="header-anchor" href="#a-scan-failed-or-completed-with-errors-on-a-corrupt-or-unreadable-media-file" aria-label="Permalink to &quot;A scan failed or completed with errors on a corrupt or unreadable media file&quot;">​</a></h2><p>Foldergram can now handle this in two different ways, depending on <code>SCAN_MEDIA_ERROR_MODE</code>.</p><p>Default behavior:</p><ul><li><code>SCAN_MEDIA_ERROR_MODE=skip</code> reports supported-media failures and continues scanning the rest of the library</li><li>the completed run is marked <code>completed_with_errors</code></li><li><code>Settings -&gt; Scan &amp; Library</code> shows the admin-only report path for that run</li><li>the full per-run report is written under <code>&lt;DATA_ROOT&gt;/scan-errors/</code></li></ul><p>Strict behavior:</p><ul><li><code>SCAN_MEDIA_ERROR_MODE=fail</code> stops on the first supported-media failure and marks the scan as failed</li></ul><p>This applies to supported media that reaches scan processing, including supported images and videos. Unsupported extensions, excluded folders, hidden paths, and files placed directly in <code>GALLERY_ROOT</code> are still ignored before this stage.</p><h2 id="moments-are-missing-and-highlights-appear-instead" tabindex="-1">Moments are missing and highlights appear instead <a class="header-anchor" href="#moments-are-missing-and-highlights-appear-instead" aria-label="Permalink to &quot;Moments are missing and highlights appear instead&quot;">​</a></h2><p>That is expected when the library does not have enough EXIF-backed timestamps.</p><p>Foldergram switches to Highlights unless it has:</p><ul><li>at least <code>24</code> indexed posts</li><li>at least <code>18</code> EXIF-backed posts</li><li>at least <code>30%</code> EXIF coverage</li></ul><h2 id="a-folder-named-stories-stopped-appearing-as-a-normal-album" tabindex="-1">A folder named <code>stories</code> stopped appearing as a normal album <a class="header-anchor" href="#a-folder-named-stories-stopped-appearing-as-a-normal-album" aria-label="Permalink to &quot;A folder named \`stories\` stopped appearing as a normal album&quot;">​</a></h2><p>That is expected when Foldergram is using the default reserved-stories mode.</p><p>In that mode, <code>AppFolder/stories</code> is reinterpreted as folder-story data instead of a standalone app folder.</p><p>If you want folders literally named <code>stories</code> to remain ordinary app folders:</p><ol><li>open <code>Settings -&gt; General Settings</code></li><li>enable <code>Treat stories folders as normal app folders</code></li><li>save the change</li><li>run a scan from <code>Settings -&gt; Scan &amp; Library</code></li></ol><h2 id="a-folder-is-still-showing-up-after-i-excluded-it" tabindex="-1">A folder is still showing up after I excluded it <a class="header-anchor" href="#a-folder-is-still-showing-up-after-i-excluded-it" aria-label="Permalink to &quot;A folder is still showing up after I excluded it&quot;">​</a></h2><p>Folder exclusions can come from:</p><ul><li><code>GALLERY_EXCLUDED_FOLDERS</code> in <code>.env</code> or Docker Compose</li><li>custom rules in <code>Settings -&gt; General Settings</code></li></ul><p>Check:</p><ul><li>rules without a slash match folder names anywhere in the gallery tree</li><li>rules with a slash match one exact relative path below <code>GALLERY_ROOT</code></li><li>env-backed rules require a restart to change</li><li>custom rules require <code>Save changes</code>, then a full scan from <code>Settings -&gt; Scan &amp; Library</code></li></ul><p>If the folder was already indexed before the rule existed, it will stay visible until that scan finishes and soft-removes it from the index.</p><h2 id="videos-or-animated-avif-files-fail-to-index-or-generate-previews" tabindex="-1">Videos or animated AVIF files fail to index or generate previews <a class="header-anchor" href="#videos-or-animated-avif-files-fail-to-index-or-generate-previews" aria-label="Permalink to &quot;Videos or animated AVIF files fail to index or generate previews&quot;">​</a></h2><p>Check that both tools are installed and available on <code>PATH</code>:</p><ul><li><code>ffprobe</code></li><li><code>ffmpeg</code></li></ul><p>Foldergram uses them directly for supported video files and animated AVIF image-sequence processing. Static AVIF files use the normal image path and do not require these tools.</p><h2 id="a-video-opens-from-the-original-file-instead-of-a-generated-preview" tabindex="-1">A video opens from the original file instead of a generated preview <a class="header-anchor" href="#a-video-opens-from-the-original-file-instead-of-a-generated-preview" aria-label="Permalink to &quot;A video opens from the original file instead of a generated preview&quot;">​</a></h2><p>That is a normal optimization. Foldergram streams the original file directly when the video is already suitable for browser playback under the current size and codec rules.</p><p>See <a href="/media-processing">Media Processing</a> for the exact conditions.</p><h2 id="the-development-watcher-is-not-reacting" tabindex="-1">The development watcher is not reacting <a class="header-anchor" href="#the-development-watcher-is-not-reacting" aria-label="Permalink to &quot;The development watcher is not reacting&quot;">​</a></h2><p>The watcher is not a permanent always-on background process for every startup path. It is development-only and is started by the scan and rebuild flows.</p><p>If needed:</p><ol><li>run a manual scan from Settings</li><li>make your filesystem change again</li></ol><h2 id="likes-disappeared-after-a-rebuild" tabindex="-1">Likes disappeared after a rebuild <a class="header-anchor" href="#likes-disappeared-after-a-rebuild" aria-label="Permalink to &quot;Likes disappeared after a rebuild&quot;">​</a></h2><p>That is expected for <code>Rebuild Library Index</code>. The rebuild resets the indexed library tables, including <code>likes</code>.</p><p>Thumbnail-only rebuilds do not clear likes.</p><h2 id="docs-build-fails" tabindex="-1">Docs build fails <a class="header-anchor" href="#docs-build-fails" aria-label="Permalink to &quot;Docs build fails&quot;">​</a></h2><p>Use the root command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:docs</span></span></code></pre></div><p>If it fails, check for:</p><ul><li>broken internal links</li><li>invalid frontmatter</li><li>mistakes in <code>docs/.vitepress/config.ts</code></li></ul><h2 id="the-app-still-behaves-oddly-in-development-after-frontend-changes" tabindex="-1">The app still behaves oddly in development after frontend changes <a class="header-anchor" href="#the-app-still-behaves-oddly-in-development-after-frontend-changes" aria-label="Permalink to &quot;The app still behaves oddly in development after frontend changes&quot;">​</a></h2><p>The client actively unregisters previously installed service workers in development. Reload once after startup if you previously visited a production build from the same origin and the browser still has stale cached assets.</p>`,84)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
